import { useState, useEffect, useRef } from "react";
import { THEMES, FONT, TECH_FONT } from "./utils";
import { SIM_REGISTRY, CATEGORIES } from "./sims";
import "./styles/global.css";

/* Skeleton loader for lazy-loaded simulations */
function SimSkeleton({ color }) {
  const fallback = color || THEMES.dark.accent;

  return (
    <div
      style={{
        padding: "40px 20px",
        textAlign: "center",
        borderRadius: 14,
        background: `${fallback}08`,
        border: `1px solid ${fallback}20`,
        animation: "pulse 1.5s ease-in-out infinite",
      }}
    >
      <div
        style={{
          fontFamily: TECH_FONT,
          fontSize: 11,
          fontWeight: 800,
          color: fallback,
          letterSpacing: 2,
          opacity: 0.6,
        }}
      >
        LOADING SIMULATION...
      </div>
    </div>
  );
}

export default function App() {
  const [activeSim, setActiveSim] = useState("rocket");
  const [catFilter, setCatFilter] = useState("all");
  const [theme, setTheme] = useState(() => {
    if (typeof window === "undefined") return "dark";
    const saved = window.localStorage.getItem("theme");
    if (saved === "light" || saved === "dark") return saved;
    return window.matchMedia("(prefers-color-scheme: dark)").matches ? "dark" : "light";
  });

  const currentTheme = THEMES[theme];
  const [compareMode, setCompareMode] = useState(false);

  useEffect(() => {
    document.body.dataset.theme = theme;
    window.localStorage.setItem("theme", theme);
  }, [theme]);

  useEffect(() => {
    setCompareMode(false);
  }, [activeSim]);

  const toggleTheme = () => setTheme((prev) => (prev === "dark" ? "light" : "dark"));

  const filtered =
    catFilter === "all"
      ? SIM_REGISTRY
      : SIM_REGISTRY.filter((s) => s.cat === catFilter);

  const active = SIM_REGISTRY.find((s) => s.id === activeSim);
  const ActiveComp = active?.comp;

  // Swipe gestures
  const [touchStart, setTouchStart] = useState(null);
  const onTouchStart = (e) => setTouchStart(e.targetTouches[0].clientX);
  const onTouchEnd = (e) => {
    if (touchStart === null) return;
    const touchEnd = e.changedTouches[0].clientX;
    const dir = touchStart - touchEnd;
    if (Math.abs(dir) > 50) {
      const idx = filtered.findIndex((s) => s.id === activeSim);
      if (dir > 0 && idx < filtered.length - 1) setActiveSim(filtered[idx + 1].id);
      if (dir < 0 && idx > 0) setActiveSim(filtered[idx - 1].id);
    }
    setTouchStart(null);
  };

  // Exhibition Mode (Fullscreen + Wake Lock)
  const [exhibition, setExhibition] = useState(false);
  const wakeLockRef = useRef(null);

  const toggleExhibition = async () => {
    try {
      if (!exhibition) {
        if (document.documentElement.requestFullscreen) await document.documentElement.requestFullscreen();
        if ("wakeLock" in navigator) wakeLockRef.current = await navigator.wakeLock.request("screen");
        setExhibition(true);
      } else {
        if (document.exitFullscreen) await document.exitFullscreen();
        if (wakeLockRef.current) {
          await wakeLockRef.current.release();
          wakeLockRef.current = null;
        }
        setExhibition(false);
      }
    } catch (err) {
      console.warn("Exhibition mode fully permitted only upon user gesture.", err);
    }
  };

  const appBgStart = theme === "dark" ? "#0a192f" : currentTheme.cardAlt;

  return (
    <div
      onTouchStart={onTouchStart}
      onTouchEnd={onTouchEnd}
      style={{
        minHeight: "100vh",
        background: `radial-gradient(circle at 50% 0%, ${appBgStart} 0%, ${currentTheme.bg} 100%)`,
        color: currentTheme.white,
        fontFamily: FONT,
        padding: "14px 10px 48px",
        maxWidth: "100%",
        margin: "0 auto",
        position: "relative",
        overflowX: "hidden",
      }}
    >
      {/* Decorative blobs */}
      <div style={{
        position: "fixed", top: "-10%", left: "-10%",
        width: "40%", height: "40%",
        background: `${currentTheme.accent}08`, filter: "blur(100px)",
        borderRadius: "50%", pointerEvents: "none", zIndex: 0,
      }} />
      <div style={{
        position: "fixed", bottom: "10%", right: "-10%",
        width: "30%", height: "30%",
        background: `${currentTheme.pink}05`, filter: "blur(80px)",
        borderRadius: "50%", pointerEvents: "none", zIndex: 0,
      }} />

      {/* Skip-to-content for keyboard users */}
      <a
        href="#active-sim"
        style={{
          position: "absolute", top: -40, left: 8, zIndex: 100,
          background: currentTheme.accent, color: currentTheme.bg, padding: "6px 12px",
          borderRadius: 6, fontSize: 12, fontWeight: 700,
          transition: "top 0.2s",
        }}
        onFocus={(e) => { e.currentTarget.style.top = "8px"; }}
        onBlur={(e) => { e.currentTarget.style.top = "-40px"; }}
      >
        Skip to simulation
      </a>

      {/* Header */}
      <header style={{ textAlign: "center", marginBottom: 20, paddingTop: 8, position: "relative", zIndex: 1 }}>
        <div style={{ position: "absolute", top: 0, right: 0, display: "flex", gap: 8 }}>
          <button
            type="button"
            onClick={toggleTheme}
            style={{
              background: currentTheme.glass,
              border: `1px solid ${currentTheme.glassBorder}`,
              color: currentTheme.accent,
              padding: "5px 10px", borderRadius: 8,
              fontFamily: TECH_FONT, fontSize: 8, fontWeight: 800,
              cursor: "pointer", touchAction: "manipulation",
              letterSpacing: 1,
            }}
          >
            {theme === "dark" ? "LIGHT MODE" : "DARK MODE"}
          </button>
          {ActiveComp && (
            <button
              type="button"
              onClick={() => setCompareMode((prev) => !prev)}
              style={{
                padding: "6px 12px", borderRadius: 8,
                border: `1px solid ${currentTheme.glassBorder}`,
                background: compareMode ? `${currentTheme.accent}20` : currentTheme.glass,
                color: compareMode ? currentTheme.accent : currentTheme.gray,
                fontFamily: TECH_FONT, fontSize: 9, fontWeight: 700,
                cursor: "pointer", letterSpacing: 1,
              }}
            >
              {compareMode ? "Γ£ò SINGLE" : "Γçä COMPARE"}
            </button>
          )}
          <button
            type="button"
            onClick={toggleExhibition}
            style={{
              background: exhibition ? `${currentTheme.red}20` : currentTheme.glass,
              border: `1px solid ${exhibition ? currentTheme.red : currentTheme.glassBorder}`,
              color: exhibition ? currentTheme.red : currentTheme.gray,
              padding: "5px 10px", borderRadius: 8,
              fontFamily: TECH_FONT, fontSize: 8, fontWeight: 800,
              cursor: "pointer", touchAction: "manipulation",
              letterSpacing: 1,
            }}
          >
            {exhibition ? "EXIT EXHIBIT MODE" : "ENTER EXHIBIT MODE"}
          </button>
        </div>
        <div style={{
          fontSize: "clamp(8px, 2.5vw, 11px)",
          color: currentTheme.accent,
          letterSpacing: 3,
          fontWeight: 800,
          textTransform: "uppercase",
          textShadow: `0 0 10px ${currentTheme.accent}30`,
        }}>
          HEMCE-2026 ΓÇó 15TH INTERNATIONAL CONFERENCE & EXHIBITS
        </div>
        <div style={{
          fontSize: "clamp(18px, 5.5vw, 28px)",
          fontWeight: 900,
          color: currentTheme.white,
          fontFamily: TECH_FONT,
          letterSpacing: 1,
          marginTop: 5,
          background: `linear-gradient(to bottom, #fff, ${currentTheme.gray})`,
          WebkitBackgroundClip: "text",
          WebkitTextFillColor: "transparent",
        }}>
          SIMULATION HUB
        </div>
        <div style={{
          width: 44, height: 3,
          background: `linear-gradient(90deg, ${currentTheme.accent}, ${currentTheme.pink})`,
          margin: "10px auto 0",
          borderRadius: 2,
          boxShadow: `0 0 10px ${currentTheme.accent}40`,
        }} />
        <div style={{ fontSize: "clamp(8px, 2.2vw, 10px)", color: currentTheme.dimText, marginTop: 6, fontWeight: 500 }}>
          ORGANISED BY HEMSI IN ASSOCIATION WITH DRDO & ISRO
        </div>
      </header>

      {/* Category filter */}
      <nav
        aria-label="Filter simulations by category"
        className="no-scrollbar"
        style={{
          display: "flex",
          gap: 6,
          marginBottom: 14,
          overflowX: "auto",
          paddingBottom: 6,
          position: "relative",
          zIndex: 1,
        }}
      >
        {CATEGORIES.map((c) => (
          <Pill key={c.id} active={catFilter === c.id} onClick={() => setCatFilter(c.id)} color={c.color} label={`Filter: ${c.label}`}>
            {c.label}
          </Pill>
        ))}
      </nav>

      {/* Sim grid */}
      <div
        role="list"
        aria-label="Available simulations"
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(auto-fill, minmax(115px, 1fr))",
          gap: 12,
          marginBottom: 20,
          position: "relative",
          zIndex: 1,
        }}
      >
        {filtered.map((s) => (
          <button
            type="button"
            role="listitem"
            aria-current={activeSim === s.id ? "true" : undefined}
            key={s.id}
            onClick={() => setActiveSim(s.id)}
            style={{
              padding: "14px 6px",
              borderRadius: 14,
              border: activeSim === s.id ? `2px solid ${s.color}` : `1px solid ${currentTheme.glassBorder}`,
              background: activeSim === s.id ? `${s.color}15` : currentTheme.glass,
              backdropFilter: "blur(10px)",
              WebkitBackdropFilter: "blur(10px)",
              color: activeSim === s.id ? s.color : currentTheme.white,
              fontFamily: TECH_FONT,
              fontSize: "clamp(9px, 2.5vw, 11px)",
              fontWeight: 700,
              cursor: "pointer",
              transition: "all .25s cubic-bezier(0.4, 0, 0.2, 1)",
              textAlign: "center",
              display: "flex",
              flexDirection: "column",
              alignItems: "center",
              gap: 4,
              boxShadow: activeSim === s.id ? `0 6px 18px ${s.color}25` : "0 2px 8px rgba(0,0,0,0.15)",
              transform: activeSim === s.id ? "scale(1.03)" : "scale(1)",
              touchAction: "manipulation",
              WebkitTapHighlightColor: "transparent",
              minHeight: 72,
            }}
            onTouchStart={(e) => { if (activeSim !== s.id) e.currentTarget.style.opacity = "0.75"; }}
            onTouchEnd={(e) => { e.currentTarget.style.opacity = "1"; }}
          >
            <div style={{
              fontSize: 22,
              marginBottom: 2,
              filter: activeSim === s.id ? `drop-shadow(0 0 8px ${s.color}60)` : "grayscale(0.4)",
              transition: "all .25s",
            }}>{s.icon}</div>
            <div style={{ lineHeight: 1.2, fontSize: "clamp(9px, 2.5vw, 11px)" }}>{s.label}</div>
          </button>
        ))}
      </div>

      {/* Active simulation panel */}
      {ActiveComp && (
        <div
          id="active-sim"
          style={{
            background: currentTheme.card,
            backdropFilter: "blur(20px)",
            WebkitBackdropFilter: "blur(20px)",
            borderRadius: 18,
            padding: "14px 10px",
            border: `1px solid ${currentTheme.accent}20`,
            boxShadow: `0 15px 30px rgba(0,0,0,0.3), inset 0 0 20px ${currentTheme.accent}05`,
            position: "relative",
            zIndex: 1,
            width: "100%",
          }}
        >
          {/* Panel header */}
          <div style={{
            fontSize: "clamp(13px, 3.5vw, 17px)",
            fontWeight: 900,
            color: currentTheme.white,
            fontFamily: TECH_FONT,
            marginBottom: 14,
            display: "flex",
            alignItems: "center",
            gap: 10,
            borderBottom: `1px solid ${active.color}20`,
            paddingBottom: 10,
          }}>
            <span style={{ fontSize: 26, filter: `drop-shadow(0 0 10px ${active.color}80)` }}>
              {active.icon}
            </span>
            <div style={{ display: "flex", flexDirection: "column" }}>
              <span style={{ fontSize: "clamp(8px, 2vw, 10px)", color: active.color, letterSpacing: 2, fontWeight: 800 }}>
                ACTIVE SIMULATION
              </span>
              {active.label}
            </div>
          </div>
          <ErrorBoundary color={active.color}>
            <Suspense fallback={<SimSkeleton color={active.color} />}>
              {compareMode ? (
                <div style={{ display: "grid", gridTemplateColumns: typeof window !== "undefined" && window.innerWidth < 600 ? "1fr" : "1fr 1fr", gap: 12 }}>
                  <div style={{ borderRight: typeof window !== "undefined" && window.innerWidth < 600 ? "none" : `1px solid ${currentTheme.glassBorder}`, paddingRight: 8 }}>
                    <div style={{ fontSize: 9, color: currentTheme.accent, fontFamily: TECH_FONT, marginBottom: 6, textAlign: "center" }}>
                      CONFIG A
                    </div>
                    <ActiveComp key={`${activeSim}-a`} />
                  </div>
                  <div style={{ paddingLeft: 8 }}>
                    <div style={{ fontSize: 9, color: currentTheme.green, fontFamily: TECH_FONT, marginBottom: 6, textAlign: "center" }}>
                      CONFIG B
                    </div>
                    <ActiveComp key={`${activeSim}-b`} />
                  </div>
                </div>
              ) : (
                <ActiveComp />
              )}
            </Suspense>
          </ErrorBoundary>
        </div>
      )}

      {/* Topic tags */}
      {active && (
        <div style={{
          marginTop: 10,
          display: "flex",
          gap: 6,
          flexWrap: "wrap",
          position: "relative",
          zIndex: 1,
        }}>
          {active.tags.map((t) => (
            <span
              key={t}
              style={{
                fontSize: "clamp(8px, 2vw, 10px)",
                padding: "4px 10px",
                borderRadius: 20,
                background: `${active.color}12`,
                color: active.color,
                border: `1px solid ${active.color}28`,
                fontFamily: TECH_FONT,
                fontWeight: 700,
                letterSpacing: 0.5,
              }}
            >
              {t}
            </span>
          ))}
        </div>
      )}

      {/* About TSPL */}
      <div style={{
        marginTop: 40,
        padding: "24px 16px",
        borderRadius: 16,
        background: `linear-gradient(135deg, ${currentTheme.card}, ${currentTheme.bg})`,
        border: `1px solid ${currentTheme.glassBorder}`,
        position: "relative",
        zIndex: 1,
        textAlign: "center"
      }}>
        <div style={{ color: currentTheme.accent, fontFamily: TECH_FONT, fontSize: 11, fontWeight: 800, letterSpacing: 2, marginBottom: 8 }}>
          TECHNOLOGY PARTNER
        </div>
        <div style={{ color: currentTheme.white, fontSize: 16, fontWeight: 700, marginBottom: 14 }}>
          Thermal Systems Hyderabad Pvt. Ltd. (TSPL)
        </div>
        <p style={{ color: currentTheme.gray, fontSize: 12, lineHeight: 1.6, maxWidth: 600, margin: "0 auto", marginBottom: 16 }}>
          With nearly four decades of expertise, TSPL is a global leader in designing, engineering, and delivering turnkey Waste Heat Recovery Solutions. Having successfully executed over 400+ projects across 40 countries, they specialize in high-energy thermal management and complex boilers for the world's most demanding continuous process operations.
        </p>
        <a href="https://www.thermalindia.com" target="_blank" rel="noopener noreferrer" style={{
          display: "inline-block",
          padding: "8px 16px",
          borderRadius: 20,
          background: `${currentTheme.accent}15`,
          border: `1px solid ${currentTheme.accent}40`,
          color: currentTheme.accent,
          fontFamily: TECH_FONT,
          fontSize: 10,
          fontWeight: 700,
          textDecoration: "none",
          letterSpacing: 1
        }}>
          EXPLORE THERMALINDIA.COM
        </a>
      </div>

      {/* Footer */}
      <div style={{
        textAlign: "center",
        marginTop: 28,
        fontSize: "clamp(8px, 2.2vw, 10px)",
        color: currentTheme.dimText,
        lineHeight: 1.9,
        position: "relative",
        zIndex: 1,
      }}>
        <div style={{
          background: `linear-gradient(90deg, transparent, ${currentTheme.dimText}40, transparent)`,
          height: 1, width: "100%", marginBottom: 14,
        }} />
        SCAN QR AT BOOTH ΓÇó INTERACT ON MOBILE
        <br />
        <strong style={{ color: currentTheme.gray }}>HEMCE-2026</strong> ΓÇó APRIL 29 ΓÇô MAY 1, 2026
        <br />
        LEONIA HOLISTIC DESTINATION ΓÇó SHAMIRPET, HYDERABAD
        <br />
        <a href="https://www.hemsindia.co.in/hemce2026" target="_blank" rel="noopener noreferrer" style={{ color: currentTheme.accent, textDecoration: "none", marginTop: 4, display: "inline-block" }}>
          WWW.HEMSINDIA.CO.IN/HEMCE2026
        </a>
      </div>
      <Analytics />
    </div>
  );
}

import { useState, useRef, useEffect, useCallback } from "react";
import { T, TECH_FONT, useCanvas, getCanvasTheme } from "../utils";

export default function ExplosiveDetectionSim() {
  const [method, setMethod] = useState("colorimetric");
  const [sample, setSample] = useState("rdx");
  const [scanning, setScanning] = useState(false);
  const [result, setResult] = useState(null);
  const [scanProg, setScanProg] = useState(0);
  const animRef = useRef(null);

  const methods = {
    colorimetric: { time: 2, sensitivity: "ppm", fp: 5 },
    spectroscopic: { time: 4, sensitivity: "ppb", fp: 1 },
    canine: { time: 1, sensitivity: "ppt", fp: 8 },
    ion_mobility: { time: 3, sensitivity: "ppb", fp: 2 },
  };
  const samples = {
    rdx: { color: T.red, name: "RDX", det: true },
    tnt: { color: T.gold, name: "TNT", det: true },
    petn: { color: T.orange, name: "PETN", det: true },
    clean: { color: T.green, name: "Clean", det: false },
    fertilizer: { color: "#8B7355", name: "AN Fert", det: method !== "canine" },
  };
  const m = methods[method], s = samples[sample];

  const startScan = () => {
    if (scanning) return;
    setScanning(true); setResult(null); setScanProg(0);
    const start = performance.now();
    const tick = (now) => {
      const p = Math.min((now - start) / (m.time * 1000), 1);
      setScanProg(p);
      if (p < 1) animRef.current = requestAnimationFrame(tick);
      else { setScanning(false); setResult(s.det ? "DETECTED" : "CLEAR"); }
    };
    animRef.current = requestAnimationFrame(tick);
  };

  useEffect(() => () => cancelAnimationFrame(animRef.current), []);

  const buildPrompt = useCallback(() =>
    `Explosive detection simulation ΓÇö current parameters:
ROLE: "You are an expert in explosive detection. You have deep knowledge of DRDO, HEMRL, and Indian defense R&D programs."

PARAMETERS (numbered):
1. Detection method: ${method} (${method === "colorimetric" ? "HEMRL field kit" : method === "spectroscopic" ? "Raman spectroscopy" : method === "ion_mobility" ? "Ion Mobility Spectrometry" : "Canine olfaction"})
2. Sample type: ${s.name}
3. Detection achieved: ${result ?? "not yet scanned"}
4. Method sensitivity: ${m.sensitivity}
5. False positive rate: ${m.fp}%
6. Scan time: ${m.time} s

ANALYSIS REQUEST:
Part 1 ΓÇö PERFORMANCE: Analyze these parameters. Are they realistic? What performance regime do they represent (low/medium/high)? What is the efficiency?
Part 2 ΓÇö SAFETY & RISK: What are the safety margins? What failure modes exist at these conditions? What would a test engineer watch for?
Part 3 ΓÇö INDIA-SPECIFIC CONTEXT: How does this relate to DRDO/HEMRL programs? Reference specific Indian systems (e.g., Agni, BrahMos, Pinaka, SMART, Astra, Nag, Akash) where applicable. What are India's current capabilities and gaps in this domain?`,
  [method, s, result, m]);

  const canvasRef = useCanvas((ctx, W, H) => {
    const theme = getCanvasTheme();

    // Technical background
    const bg = ctx.createRadialGradient(W/2, H/2, 0, W/2, H/2, W/2);
    bg.addColorStop(0, theme.canvasBackground);
    bg.addColorStop(1, theme.canvasSurface);
    ctx.fillStyle = bg;
    ctx.fillRect(0, 0, W, H);

    const cx = W / 2, cy = H / 2;
    
    // Sample Container (Suitcase/Package)
    ctx.fillStyle = "#1A202C";
    ctx.strokeStyle = `${T.accent}30`;
    ctx.lineWidth = 2;
    ctx.beginPath(); ctx.roundRect(W/2 - 60, cy - 40, 120, 80, 8); ctx.fill(); ctx.stroke();
    
    // Sample Interior (The chemical signature area)
    ctx.fillStyle = `${s.color}15`;
    ctx.fillRect(W/2 - 50, cy - 30, 100, 60);

    // Scanner Beam
    if (scanning) {
      const beamY = cy - 40 + scanProg * 80;
      const beamGrad = ctx.createLinearGradient(W/2 - 60, beamY, W/2 + 60, beamY);
      beamGrad.addColorStop(0, "transparent");
      beamGrad.addColorStop(0.5, method === "spectroscopic" ? T.purple : T.cyan);
      beamGrad.addColorStop(1, "transparent");
      
      ctx.strokeStyle = beamGrad;
      ctx.lineWidth = 3;
      ctx.beginPath(); ctx.moveTo(W/2 - 65, beamY); ctx.lineTo(W/2 + 65, beamY); ctx.stroke();
      
      // Beam Glow
      ctx.globalAlpha = 0.2;
      ctx.fillStyle = method === "spectroscopic" ? T.purple : T.cyan;
      ctx.fillRect(W/2 - 60, beamY - 5, 120, 10);
      ctx.globalAlpha = 1;

      // Sampling Particles (for IMS/Canine)
      if (method === "ion_mobility" || method === "canine") {
        for(let i=0; i<5; i++) {
          const px = W/2 - 60 + Math.random() * 120;
          const py = beamY + (Math.random() - 0.5) * 10;
          ctx.fillStyle = s.color;
          ctx.beginPath(); ctx.arc(px, py, 1, 0, Math.PI * 2); ctx.fill();
        }
      }
    }

    // Spectrum Analyzer (Bottom)
    const gx = 20, gy = H - 35, gw = W - 40, gh = 25;
    ctx.strokeStyle = `${T.accent}20`;
    ctx.strokeRect(gx, gy, gw, gh);
    
    if (scanning || result) {
      ctx.strokeStyle = scanning ? T.accent : result === "DETECTED" ? T.red : T.green;
      ctx.lineWidth = 1.5;
      ctx.beginPath();
      ctx.moveTo(gx, gy + gh);
      for(let x=0; x<gw; x+=2) {
        let iy = Math.sin(x * 0.2 + performance.now() / 100) * 2;
        // Peak for detected explosive
        if (s.det && Math.abs(x - gw/2) < 20) {
          iy -= (scanning ? scanProg : 1) * 15 * Math.sin((x - (gw/2 - 20)) / 40 * Math.PI);
        }
        ctx.lineTo(gx + x, gy + gh * 0.8 + iy);
      }
      ctx.stroke();
    }

    // Detection HUD Overlay
    if (result === "DETECTED") {
      ctx.strokeStyle = T.red;
      ctx.lineWidth = 2;
      ctx.strokeRect(W/2 - 65, cy - 45, 130, 90);
      
      // Target Reticle corners
      const rSize = 10;
      ctx.beginPath();
      ctx.moveTo(W/2 - 65, cy - 35); ctx.lineTo(W/2 - 65, cy - 45); ctx.lineTo(W/2 - 55, cy - 45);
      ctx.moveTo(W/2 + 65, cy - 35); ctx.lineTo(W/2 + 65, cy - 45); ctx.lineTo(W/2 + 55, cy - 45);
      ctx.moveTo(W/2 - 65, cy + 35); ctx.lineTo(W/2 - 65, cy + 45); ctx.lineTo(W/2 - 55, cy + 45);
      ctx.moveTo(W/2 + 65, cy + 35); ctx.lineTo(W/2 + 65, cy + 45); ctx.lineTo(W/2 + 55, cy + 45);
      ctx.stroke();

      ctx.font = `900 10px ${TECH_FONT}`;
      ctx.fillStyle = T.red;
      ctx.textAlign = "center";
      ctx.fillText("! THREAT IDENTIFIED: " + s.name.toUpperCase(), W/2, cy - 50);
      ctx.textAlign = "left";
    } else if (result === "CLEAR") {
      ctx.font = `900 10px ${TECH_FONT}`;
      ctx.fillStyle = T.green;
      ctx.textAlign = "center";
      ctx.fillText("Γ£ô SAMPLE VERIFIED: STABLE", W/2, cy - 50);
      ctx.textAlign = "left";
    }

    // Status / Mode Labels
    ctx.font = `800 8px ${TECH_FONT}`;
    ctx.fillStyle = T.dimText;
    ctx.fillText(`METHOD: ${method.toUpperCase()}`, 20, 15);
    ctx.fillText(`SENSITIVITY: ${m.sensitivity.toUpperCase()}`, W - 100, 15);

  }, [scanning, scanProg, result, method, sample, s, m],
    { animate: true }
  );

  return (
    <div>
      <SimCanvas canvasRef={canvasRef} width={380} height={180} maxWidth={380} />
      <PillRow>
        <Pill active={method === "colorimetric"} onClick={() => { setResult(null); setMethod("colorimetric"); }} color={T.orange}>Colorimetric</Pill>
        <Pill active={method === "spectroscopic"} onClick={() => { setResult(null); setMethod("spectroscopic"); }} color={T.purple}>Raman</Pill>
        <Pill active={method === "ion_mobility"} onClick={() => { setResult(null); setMethod("ion_mobility"); }} color={T.accent}>IMS</Pill>
        <Pill active={method === "canine"} onClick={() => { setResult(null); setMethod("canine"); }} color={T.gold}>Canine ≡ƒÉò</Pill>
      </PillRow>
      <PillRow>
        {Object.entries(samples).map(([k, v]) => (
          <Pill key={k} active={sample === k} onClick={() => { setResult(null); setSample(k); }} color={v.color}>{v.name}</Pill>
        ))}
      </PillRow>
      <DataRow>
        <DataBox label="Scan Time" value={m.time} unit="s" color={T.accent} />
        <DataBox label="Sensitivity" value={m.sensitivity} color={T.green} />
        <DataBox label="False +" value={`${m.fp}%`} color={m.fp > 5 ? T.gold : T.green} />
      </DataRow>
      <div style={{ display: "flex", gap: 8 }}>
        <ActionBtn onClick={startScan} disabled={scanning} color={T.accent}>
          {scanning ? `SCANNING... ${(scanProg * 100).toFixed(0)}%` : "≡ƒö¼ SCAN SAMPLE"}
        </ActionBtn>
      </div>
      <InfoBox><strong style={{ color: T.purple }}>Detection:</strong> {method === "colorimetric" ? "HEMRL field kit ΓÇö color reagents, used by police/BSF." : method === "spectroscopic" ? "Raman ΓÇö laser molecular fingerprinting, ppb sensitivity." : method === "ion_mobility" ? "IMS ΓÇö airport-grade screening, low false-positive." : "Canine ΓÇö ppt sensitivity, gold standard for field sweeps."}</InfoBox>
      <AIInsight buildPrompt={buildPrompt} color={T.pink} />
      <ExportBtn simId="explosive_detection" getData={() => ({ method, sample, scanning, result, scanProg, sensitivity: samples[sample].sensitivity })} color={T.pink} />
    </div>
  );
}

import { useState, useRef } from "react";
import { useCanvas, T } from "../utils";

export function GreenPropellantSim() {
  const [phase, setPhase] = useState("idle"); // idle | mixing | complete
  const [tech, setTech] = useState("adn"); // adn | han | gap
  const progressRef = useRef(0);
  const particlesRef = useRef([]);

  const initParticles = () => {
    particlesRef.current = Array.from({ length: 150 }).map(() => ({
      x: Math.random() * 460,
      y: Math.random() * 180,
      vx: (Math.random() - 0.5) * 2,
      vy: (Math.random() - 0.5) * 2,
      size: Math.random() * 3 + 1,
      type: Math.random() > 0.5 ? 'oxidizer' : 'fuel',
      alpha: Math.random() * 0.5 + 0.3
    }));
  };

  if (particlesRef.current.length === 0) initParticles();

  const canvasRef = useCanvas((ctx, frameCount) => {
    ctx.clearRect(0, 0, 460, 180);

    const isMixing = phase === "mixing";
    if (isMixing) {
      progressRef.current = Math.min(progressRef.current + 0.005, 1);
      if (progressRef.current >= 1) setPhase("complete");
    }

    particlesRef.current.forEach((p, i) => {
      // Movement
      if (isMixing) {
        // Vortex effect simulating nanoscale energetic mixing
        const cx = 230, cy = 90;
        const angle = Math.atan2(p.y - cy, p.x - cx);
        const dist = Math.hypot(p.x - cx, p.y - cy);

        p.x -= Math.sin(angle) * (dist * 0.05);
        p.y += Math.cos(angle) * (dist * 0.05);

        // Binding to form clustered nano-energetics
        if (progressRef.current > 0.5) {
           p.x += (cx - p.x) * 0.02;
           p.y += (cy - p.y) * 0.02;
           if (p.type === 'fuel') p.type = 'bound';
        }
      } else {
        // Brownian motion
        p.x += p.vx * 0.2;
        p.y += p.vy * 0.2;
        if (p.x < 0 || p.x > 460) p.vx *= -1;
        if (p.y < 0 || p.y > 180) p.vy *= -1;
      }

      ctx.beginPath();
      ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);

      let color;
      if (p.type === 'oxidizer') color = tech === 'adn' ? '120, 255, 160' : '80, 200, 255';
      else if (p.type === 'fuel') color = '255, 200, 100'; // Nano-Al
      else color = '100, 255, 100'; // Bound green energetic

      ctx.fillStyle = `rgba(${color}, ${p.alpha})`;
      ctx.shadowColor = `rgba(${color}, 0.8)`;
      ctx.shadowBlur = isMixing ? 15 : 5;
      ctx.fill();
    });

    if (phase === "complete") {
      ctx.fillStyle = "rgba(100, 255, 120, 0.2)";
      ctx.fillRect(0, 0, 460, 180);
      ctx.fillStyle = T.white;
      ctx.font = "24px 'Space Mono'";
      ctx.textAlign = "center";
      ctx.shadowBlur = 0;
      ctx.fillText("SYNTHESIS COMPLETE", 230, 95);
    }
  }, { animate: true });

  const startMixing = () => {
    progressRef.current = 0;
    initParticles();
    setPhase("mixing");
  };

  const getStats = () => {
    if (tech === "adn") return { isp: 275, toxicity: "None", signature: "Reduced" };
    if (tech === "han") return { isp: 260, toxicity: "Low", signature: "Minimum" };
    return { isp: 245, toxicity: "None", signature: "Low" };
  };

  return (
    <div>
      <SimCanvas canvasRef={canvasRef} width={460} height={180} />

      <PillRow>
        <Pill active={tech === "adn"} onClick={() => setTech("adn")}>ADN Oxidizer</Pill>
        <Pill active={tech === "han"} onClick={() => setTech("han")}>HAN-based</Pill>
        <Pill active={tech === "gap"} onClick={() => setTech("gap")}>GAP Polymer</Pill>
      </PillRow>

      <DataRow>
        <DataBox label="Estimated Isp" value={getStats().isp} unit="s" />
        <DataBox label="Toxicity" value={getStats().toxicity} />
        <DataBox label="Exhaust Sig" value={getStats().signature} />
      </DataRow>

      <div style={{ display: "flex", gap: 8, marginTop: 14 }}>
        <ActionBtn onClick={startMixing} disabled={phase === "mixing"} color="#2ecc71">
          {phase === "mixing" ? "SYNTHESIZING..." : "SYNTHESIZE MATRIX"}
        </ActionBtn>
      </div>

      <InfoBox>
        Green energetics like Ammonium Dinitramide (ADN) and Hydroxylammonium Nitrate (HAN) replace highly toxic and corrosive Hydrazine and Ammonium Perchlorate. They burn clean, producing zero HCl (hydrochloric acid) in the exhaust signature, while delivering higher specific impulse.
      </InfoBox>

      <AIInsight buildPrompt={() => `Analyze the benefits of using ${tech.toUpperCase()} based green propellants over traditional highly toxic space and defense propulsion materials.`} />
    </div>
  );
}

import { useState, useRef, useCallback, useMemo } from "react";
import { T, TECH_FONT, MONO_FONT, useCanvas, getCanvasTheme, prng } from "../utils";

export default function HybridRocketSim() {
  const [throttle, setThrottle] = useState(50);
  const [fuel, setFuel] = useState("paraffin");
  const [oxidizer, setOxidizer] = useState("n2o");
  const [running, setRunning] = useState(false);
  const ivRef = useRef(null);

  const fd = { paraffin: { rate: 3.2, isp: 250 }, htpb: { rate: 1.0, isp: 240 }, abs: { rate: 1.5, isp: 230 } }[fuel];
  const od = { n2o: { name: "NΓééO", mult: 1.0 }, lox: { name: "LOX", mult: 1.3 }, h2o2: { name: "HΓééOΓéé", mult: 1.1 } }[oxidizer];

  const regRate = useMemo(() => (fd.rate * (throttle / 100) * od.mult).toFixed(1), [fd.rate, throttle, od.mult]);
  const optimalOF = {
    "paraffin-n2o": 7.5, "paraffin-lox": 2.8, "paraffin-h2o2": 6.0,
    "htpb-n2o": 8.0, "htpb-lox": 2.5, "htpb-h2o2": 6.5,
    "abs-n2o": 7.0, "abs-lox": 2.2, "abs-h2o2": 5.5,
  };
  const optOF = optimalOF[`${fuel}-${oxidizer}`];
  const fuelDensity = { paraffin: 900, htpb: 920, abs: 1040 }[fuel];
  const oxFlux = (throttle / 100) * od.mult * 200;
  const regRateMS = Number(regRate) * 0.001;
  const ofRatio = (oxFlux / (fuelDensity * regRateMS + 0.001)).toFixed(1);
  const ofDeviation = Math.abs(Number(ofRatio) - optOF);
  const ispPenalty = Math.min(0.3, ofDeviation * 0.05);
  const actualIsp = Math.round(fd.isp * (1 - ispPenalty));
  const thrust = Math.round(actualIsp * throttle / 100 * od.mult * 0.4);
  const ofColor = ofDeviation > optOF * 0.2 ? T.red : ofDeviation > optOF * 0.1 ? T.orange : T.green;

  const canvasRef = useCanvas((ctx, W, H, frame) => {
    const cy = H / 2;
    const theme = getCanvasTheme();
    
    // Background for test stand atmosphere
    const bg = ctx.createRadialGradient(W/2, cy, 0, W/2, cy, W);
    bg.addColorStop(0, theme.canvasBackground);
    bg.addColorStop(1, theme.canvasSurface);
    ctx.fillStyle = bg;
    ctx.fillRect(0, 0, W, H);

    // Oxidizer Tank (Cryogenic Look)
    ctx.fillStyle = "#1A3A5A";
    ctx.strokeStyle = T.accent;
    ctx.lineWidth = 1.5;
    ctx.beginPath(); ctx.roundRect(10, cy - 30, 60, 60, 8); ctx.fill(); ctx.stroke();
    
    // Tank frost effect
    ctx.strokeStyle = "rgba(255,255,255,0.05)";
    ctx.strokeRect(12, cy - 28, 56, 56);

    // Feed System / Valve
    ctx.strokeStyle = running ? T.cyan : `${T.cyan}30`;
    ctx.lineWidth = 3;
    ctx.beginPath(); ctx.moveTo(70, cy); ctx.lineTo(100, cy); ctx.stroke();
    
    // Injector Plate
    ctx.fillStyle = "#2D3748"; ctx.fillRect(95, cy - 15, 8, 30);

    // Motor Casing (Combustor)
    ctx.fillStyle = "#1A202C";
    ctx.strokeStyle = `${T.accent}30`;
    ctx.beginPath(); ctx.roundRect(103, cy - 35, 170, 70, 4); ctx.fill(); ctx.stroke();

    // Solid Fuel Grain Regression Visualization
    const fc = fuel === "paraffin" ? "#F5DEB3" : fuel === "abs" ? "#8B8682" : "#A0522D";
    const regOffset = -2 + (throttle / 100) * 12 * Math.sin(performance.now() / 1000); // Visual flair for regression
    const portH = 15 + (throttle / 100) * 10;
    
    ctx.fillStyle = fc;
    // Top Grain
    ctx.beginPath(); ctx.roundRect(107, cy - 30, 162, 30 - portH/2, 2); ctx.fill();
    // Bottom Grain
    ctx.beginPath(); ctx.roundRect(107, cy + portH/2, 162, 30 - portH/2, 2); ctx.fill();

    // Flow & Combustion Core
    if (running) {
      // Ox Flow Pulse
      const flowPulse = Math.sin(performance.now() / 50) * 0.5 + 0.5;
      ctx.strokeStyle = `rgba(0, 180, 216, ${0.4 * flowPulse})`;
      ctx.lineWidth = 4;
      ctx.beginPath(); ctx.moveTo(70, cy); ctx.lineTo(100, cy); ctx.stroke();

      // Flame Core (Purplish hybrid flame)
      const fGrad = ctx.createLinearGradient(120, 0, 260, 0);
      fGrad.addColorStop(0, T.white);
      fGrad.addColorStop(0.3, T.purple);
      fGrad.addColorStop(1, "transparent");
      
      ctx.fillStyle = fGrad;
      ctx.globalAlpha = 0.5 + (throttle / 200);
      ctx.beginPath(); 
      ctx.roundRect(110, cy - portH/2 + 2, 150 + throttle * 0.5, portH - 4, 10);
      ctx.fill();
      ctx.globalAlpha = 1;
      
      // Combustion Particles
      for (let i = 0; i < 15; i++) {
        const px = 110 + prng(frame, i * 3)     * 150;
        const py = cy + (prng(frame, i * 3 + 1) - 0.5) * portH;
        ctx.fillStyle = `rgba(138, 43, 226, ${prng(frame, i * 3 + 2)})`;
        ctx.beginPath(); ctx.arc(px, py, 1.5, 0, Math.PI * 2); ctx.fill();
      }
    }

    // Nozzle Expansion
    ctx.fillStyle = "#2D3748";
    ctx.beginPath();
    ctx.moveTo(273, cy - 15); ctx.lineTo(300, cy - 35); ctx.lineTo(300, cy + 35); ctx.lineTo(273, cy + 15);
    ctx.closePath(); ctx.fill();
    ctx.strokeStyle = `${T.accent}40`; ctx.stroke();

    // Exhaust Plume
    if (running) {
      const eGrad = ctx.createLinearGradient(300, 0, 360, 0);
      eGrad.addColorStop(0, `${T.purple}66`);
      eGrad.addColorStop(1, "transparent");
      ctx.fillStyle = eGrad;
      ctx.beginPath();
      ctx.moveTo(300, cy - 30); ctx.lineTo(360, cy - 50); ctx.lineTo(360, cy + 50); ctx.lineTo(300, cy + 30);
      ctx.fill();
    }

    // HUD Text
    ctx.font = `900 9px ${TECH_FONT}`;
    ctx.textAlign = "center";
    ctx.fillStyle = T.accent;
    ctx.fillText(od.name.toUpperCase(), 40, cy - 35);
    ctx.fillStyle = T.orange;
    ctx.fillText("COMBUSTOR: " + fuel.toUpperCase(), 188, cy - 40);
    
    ctx.font = `800 8px ${MONO_FONT}`;
    ctx.fillStyle = T.dimText;
    ctx.fillText(`THRUST VECTOR: ${running ? "STABLE" : "NULL"}`, 188, cy + 45);
    ctx.textAlign = "left";

  }, [running, throttle, fuel, oxidizer],
    { animate: true }
  );

  // Animation is driven by useCanvas with { animate: true }

  const buildPrompt = useCallback(() =>
    `Hybrid rocket motor simulation ΓÇö current parameters:
ROLE: "You are an expert in hybrid combustion. You have deep knowledge of DRDO, HEMRL, and Indian defense R&D programs."

PARAMETERS (numbered):
1. Solid fuel: ${fuel}
2. Fuel regression rate base: ${fd.rate} mm/s
3. Base fuel Isp: ${fd.isp} s
4. Liquid oxidizer: ${od.name}
5. Throttle setting: ${throttle}%
6. Fuel regression rate at current throttle: ${regRate} mm/s
7. Oxidizer/fuel ratio: ${ofRatio}
8. Optimal O/F: ${optOF}
9. O/F deviation: ${ofDeviation.toFixed(1)}
10. Actual Isp: ${actualIsp} s
11. Net thrust: ${thrust} kN
12. Engine running: ${running ? "YES" : "NO"}

ANALYSIS REQUEST:
Part 1 ΓÇö PERFORMANCE: Analyze these parameters. Are they realistic? What performance regime do they represent (low/medium/high)? What is the efficiency?
Part 2 ΓÇö SAFETY & RISK: What are the safety margins? What failure modes exist at these conditions? What would a test engineer watch for?
Part 3 ΓÇö INDIA-SPECIFIC CONTEXT: How does this relate to DRDO/HEMRL programs? Reference specific Indian systems (e.g., Agni, BrahMos, Pinaka, SMART, Astra, Nag, Akash) where applicable. What are India's current capabilities and gaps in this domain?`,
  [fuel, fd, od, throttle, regRate, ofRatio, optOF, ofDeviation, actualIsp, thrust, running]);

  return (<div>
    <SimCanvas canvasRef={canvasRef} width={370} height={120} maxWidth={370} />
    <PillRow>
      <Pill active={fuel === "paraffin"} onClick={() => setFuel("paraffin")} color={T.gold}>Paraffin</Pill>
      <Pill active={fuel === "htpb"} onClick={() => setFuel("htpb")} color={T.orange}>HTPB</Pill>
      <Pill active={fuel === "abs"} onClick={() => setFuel("abs")} color={T.gray}>ABS (3D)</Pill>
    </PillRow>
    <PillRow>
      <Pill active={oxidizer === "n2o"} onClick={() => setOxidizer("n2o")} color={T.cyan}>NΓééO</Pill>
      <Pill active={oxidizer === "lox"} onClick={() => setOxidizer("lox")} color={T.accent}>LOX</Pill>
      <Pill active={oxidizer === "h2o2"} onClick={() => setOxidizer("h2o2")} color={T.green}>HΓééOΓéé</Pill>
      <Pill active={running} onClick={() => setRunning(!running)} color={running ? T.red : T.green}>{running ? "ΓÅ╣ Stop" : "Γû╢ Run"}</Pill>
    </PillRow>
    <Slider label="Throttle" value={throttle} onChange={setThrottle} min={0} max={100} unit="%" color={T.green} />
    <DataRow>
      <DataBox label="Thrust" value={thrust} unit="kN" color={T.orange} />
      <DataBox label="Isp" value={actualIsp} unit="s" color={T.accent} />
      <DataBox label="O/F" value={ofRatio} unit="" color={ofColor} />
      <DataBox label="Reg Rate" value={regRate} unit="mm/s" color={T.gold} />
    </DataRow>
    <div style={{ fontSize: 10, color: T.dimText, textAlign: "center", marginTop: 2 }}>
      Optimal O/F for {fuel}/{oxidizer}: {optOF} ΓÇö Current: {ofRatio}{ofDeviation > optOF * 0.2 ? " ΓÜá Far from optimal" : " Γ£ô Near optimal"}
    </div>
    <InfoBox><strong style={{ color: T.green }}>Hybrid advantage:</strong> Throttleable, restartable, inherently safer. {fuel === "paraffin" ? "Paraffin: 3├ù regression rate." : fuel === "abs" ? "ABS: 3D-printable grains." : "HTPB: standard baseline."} ISRO/HEMRL co-developing hybrid motors.</InfoBox>
    <AIInsight buildPrompt={buildPrompt} color={T.lime} />
    <ExportBtn simId="hybrid" getData={() => ({ fuel, oxidizer, throttle, thrust, regRate })} color={T.lime} />
  </div>);
}

import { useState, useCallback } from "react";
import { T, TECH_FONT, MONO_FONT, useCanvas, getCanvasTheme } from "../utils";

export default function PAUTSim() {
  const [angle, setAngle] = useState(0);
  const [focal, setFocal] = useState(40);
  const [elems, setElems] = useState(32);
  const [freq, setFreq] = useState(5);
  const [defect, setDefect] = useState(true);
  const [mode, setMode] = useState("sector");
  const res = (1540 / (2 * freq * 1000)).toFixed(2);

  const canvasRef = useCanvas(
    (ctx, W, H) => {
      const theme = getCanvasTheme();
      const pw = Math.min(elems * 3, W - 60), px = (W - pw) / 2, py = 25, ph = 14, ew = pw / elems;

      ctx.fillStyle = theme.canvasBackground;
      ctx.fillRect(0, 0, W, H);

      ctx.fillStyle = "#2D3748";
      ctx.beginPath();
      ctx.roundRect(px - 6, py - 4, pw + 12, ph + 8, 4);
      ctx.fill();
      ctx.strokeStyle = `${T.accent}40`;
      ctx.lineWidth = 1;
      ctx.stroke();

      for (let i = 0; i < elems; i++) {
        const isActive = mode === "sector" || Math.abs((px + i * ew + ew/2) - (W/2 + angle * 2)) < 24;
        const phase = Math.sin((i / elems) * Math.PI + (performance.now() / 100)) * 0.5 + 0.5;

        if (isActive) {
          ctx.shadowBlur = 8;
          ctx.shadowColor = T.accent;
          ctx.fillStyle = `rgba(76, 201, 240, ${0.6 + phase * 0.4})`;
        } else {
          ctx.shadowBlur = 0;
          ctx.fillStyle = "#1a2744";
        }
        ctx.fillRect(px + i * ew + 1, py, ew - 2, ph);
        ctx.shadowBlur = 0;
      }

      const my = py + ph + 8, mh = H - my - 12;
      const bscanX = 20, bscanY = py + ph + 10;
      const bscanW = W - 40, bscanH = H - bscanY - 10;
      const imgData = ctx.createImageData(bscanW, bscanH);
      const data = imgData.data;
      const wallDepth = 0.85;
      for (let y = 0; y < bscanH; y++) {
        for (let x = 0; x < bscanW; x++) {
          const idx = (y * bscanW + x) * 4;
          const normY = y / bscanH;
          const noise = Math.sin(x * 7.13 + y * 3.37) * 10 + 5;
          const surfaceEcho = normY < 0.05 ? 200 * (1 - normY / 0.05) : 0;
          const distToWall = Math.abs(normY - wallDepth);
          const wallEcho = distToWall < 0.02 ? 180 * (1 - distToWall / 0.02) : 0;
          let defectEcho = 0;
          if (defect) {
            const defectNormX = 0.65;
            const defectNormY = 0.45;
            const dx = (x / bscanW) - defectNormX;
            const dy = normY - defectNormY;
            const distToDefect = Math.sqrt(dx * dx * 4 + dy * dy * 16);
            if (distToDefect < 0.08) {
              defectEcho = 255 * (1 - distToDefect / 0.08);
            }
          }
          const beamCenter = mode === "sector"
            ? 0.5 + Math.sin(angle * Math.PI / 180) * 0.3
            : (0.5 + angle * 0.01);
          const beamDist = Math.abs((x / bscanW) - beamCenter);
          const beamIntensity = beamDist < 0.15 ? 1.2 : 0.8;
          const intensity = Math.min(255, (noise + surfaceEcho + wallEcho + defectEcho) * beamIntensity);
          data[idx] = intensity * 0.8;
          data[idx + 1] = intensity * 0.85;
          data[idx + 2] = intensity;
          data[idx + 3] = 255;
        }
      }
      ctx.putImageData(imgData, bscanX, bscanY);
      ctx.strokeStyle = `${T.accent}30`;
      ctx.lineWidth = 1;
      ctx.strokeRect(bscanX, bscanY, bscanW, bscanH);
      ctx.font = `600 7px ${TECH_FONT}`;
      ctx.fillStyle = T.dimText;
      ctx.textAlign = "right";
      ctx.fillText("0mm", bscanX - 2, bscanY + 8);
      ctx.fillText(`${focal}mm`, bscanX - 2, bscanY + bscanH);
      ctx.fillStyle = T.accent;
      ctx.textAlign = "left";
      ctx.fillText("B-SCAN", bscanX + 4, bscanY + 10);

      const bcx = W / 2, rad = (angle * Math.PI) / 180;
      ctx.lineCap = "round";

      if (mode === "sector") {
        for (let a = -35; a <= 35; a += 5) {
          const r = (a * Math.PI) / 180;
          const isCenter = Math.abs(a - angle) < 2.5;
          ctx.strokeStyle = isCenter ? `${T.accent}CC` : `${T.accent}08`;
          ctx.lineWidth = isCenter ? 3 : 0.5;
          ctx.beginPath(); ctx.moveTo(bcx, my);
          const scale = Math.min(1, mh / (Math.cos(r) * 200));
          ctx.lineTo(bcx + Math.sin(r) * 200 * scale, my + Math.cos(r) * 200 * scale);
          ctx.stroke();
          if (isCenter) {
            ctx.strokeStyle = `${T.accent}30`;
            ctx.lineWidth = 10;
            ctx.stroke();
          }
        }
      } else {
        const sh = angle * 2.5;
        for (let i = -4; i <= 4; i++) {
          const isCenter = Math.abs(i) < 1;
          ctx.strokeStyle = isCenter ? `${T.accent}AA` : `${T.accent}10`;
          ctx.lineWidth = isCenter ? 4 : 1;
          ctx.beginPath();
          ctx.moveTo(bcx + sh + i * 14, my);
          ctx.lineTo(bcx + sh + i * 14, my + mh);
          ctx.stroke();
        }
      }

      if (defect) {
        const bx = bcx + Math.sin(rad) * ((dy - my) / Math.cos(rad || 0.001));
        const dist = Math.sqrt((bx - dx)**2);
        if (dist < 40) {
          const strength = 1 - (dist / 40);
          ctx.fillStyle = `rgba(255, 77, 109, ${strength * 0.4})`;
          ctx.beginPath(); ctx.arc(dx, dy, 20 * strength, 0, Math.PI * 2); ctx.fill();
          ctx.font = `900 10px ${TECH_FONT}`;
          ctx.fillStyle = T.red;
          ctx.textAlign = "center";
          ctx.fillText("SIGNAL ECHO", dx, dy - 18);
          ctx.textAlign = "left";
        }
      }

      ctx.font = `800 10px ${TECH_FONT}`; ctx.fillStyle = T.accent; ctx.fillText("PHASED ARRAY PROBE v4.2", px - 4, py - 10);
