      if (defect) {
        ctx.fillStyle = T.red;
        ctx.font = `800 9px ${TECH_FONT}`;
        ctx.fillText("VOLUMETRIC FLAW DETECTED", dx - 60, dy + 20);
      }
    },
    [angle, focal, elems, freq, defect, mode],
