      <DataRow>
        <DataBox label="Elements" value={elems} color={T.gold} />
        <DataBox label="Freq" value={freq} unit="MHz" color={T.green} />
        <DataBox label="Resolution" value={res} unit="mm" color={T.accent} />
      </DataRow>
      <InfoBox>
        <strong style={{ color: T.accent }}>PAUT:</strong> Electronic phasing steers beam without moving probe. {mode === "sector" ? "Sector scan sweeps angles." : "Linear scan shifts laterally."} {defect ? "Red echo = defect reflection!" : ""} Higher freq = finer resolution, less penetration.
      </InfoBox>
      <AIInsight buildPrompt={buildPrompt} color={T.green} />
      <ExportBtn simId="paut" getData={() => ({ mode, angle, focal, elems, freq, defect, res })} color={T.green} />
    </div>
  );
}

import { useState, useCallback } from "react";
import { T, TECH_FONT, MONO_FONT, useCanvas, getCanvasTheme } from "../utils";

export default function PressureVesselSim() {
  const [pressure, setPressure] = useState(5);
  const [thickness, setThickness] = useState(8);
  const [radius, setRadius] = useState(200);
  const [mat, setMat] = useState("steel");

  const ys = { steel: 700, aluminium: 280, composite: 450 }[mat];
  const hoop = (pressure * radius) / thickness;
  const axial = hoop / 2;
  const fos = ys / hoop;
  const burst = ((ys * thickness) / radius).toFixed(1);
  const safe = fos >= 1.5;
  const warn = fos >= 1 && fos < 1.5;
  const wallColor = hoop > ys ? T.red : hoop > ys * 0.67 ? T.gold : T.green;

  const canvasRef = useCanvas(
    (ctx, W, H) => {
      const cx = W / 2, cy = H / 2, p = pressure;
      const canvasTheme = getCanvasTheme();
      
      // Deep technical background
      const bg = ctx.createRadialGradient(cx, cy, 0, cx, cy, W/2);
      bg.addColorStop(0, canvasTheme.bgStart);
      bg.addColorStop(1, canvasTheme.bgEnd);
      ctx.fillStyle = bg;
      ctx.fillRect(0, 0, W, H);

      const dr = 65, ww = Math.max(4, thickness * 0.7);
      
      // Internal Stress Heatmap (Glow)
      const stressP = Math.min(1.5, hoop / ys);
      const heatGrad = ctx.createRadialGradient(cx, cy, dr - ww, cx, cy, dr + ww);
      heatGrad.addColorStop(0, "transparent");
      heatGrad.addColorStop(0.5, stressP > 1.0 ? T.red : stressP > 0.7 ? T.orange : T.green);
      heatGrad.addColorStop(1, "transparent");
      
      ctx.globalAlpha = 0.3 * stressP;
      ctx.fillStyle = heatGrad;
      ctx.beginPath(); ctx.arc(cx, cy, dr + 10, 0, Math.PI * 2); ctx.fill();
      ctx.globalAlpha = 1;

      // Composite Winding Pattern / Vessel Structure
      ctx.strokeStyle = wallColor;
      ctx.lineWidth = ww;
      ctx.beginPath(); ctx.arc(cx, cy, dr, 0, Math.PI * 2); ctx.stroke();
      
      // Fiber Winding details
      ctx.strokeStyle = "rgba(255,255,255,0.1)";
      ctx.lineWidth = 0.5;
      for(let i=0; i<36; i++) {
        const a = (i / 36) * Math.PI * 2;
        ctx.beginPath();
        ctx.moveTo(cx + Math.cos(a) * (dr - ww/2), cy + Math.sin(a) * (dr - ww/2));
        ctx.lineTo(cx + Math.cos(a + 0.4) * (dr + ww/2), cy + Math.sin(a + 0.4) * (dr + ww/2));
        ctx.stroke();
      }

      // Internal Pressure Vectors (Pulse)
      const pulse = Math.sin(performance.now() / 200) * 0.2 + 0.8;
      const pn = Math.min(pressure / 20, 1);
      ctx.strokeStyle = T.accent;
      ctx.lineWidth = 1;
      for (let i = 0; i < 12; i++) {
        const a = (i / 12) * Math.PI * 2, len = 10 + pn * 15 * pulse;
        ctx.beginPath();
        ctx.moveTo(cx + Math.cos(a) * (dr - ww/2 - 2), cy + Math.sin(a) * (dr - ww/2 - 2));
        ctx.lineTo(cx + Math.cos(a) * (dr - ww/2 - 2 - len), cy + Math.sin(a) * (dr - ww/2 - 2 - len));
        ctx.stroke();
      }

      // Safety Valve Venting (Particle Effect)
      if (stressP > 1.0) {
        ctx.fillStyle = T.white;
        for(let i=0; i<5; i++) {
          const vx = cx + Math.random() * 10 - 5;
          const vy = cy - dr - ww - Math.random() * 30;
          ctx.globalAlpha = 0.4;
          ctx.beginPath(); ctx.arc(vx, vy, 2, 0, Math.PI * 2); ctx.fill();
        }
        ctx.globalAlpha = 1;
        ctx.font = `900 8px ${MONO_FONT}`;
        ctx.fillStyle = T.red;
        ctx.fillText("VALVE VENTING", cx + dr, cy - dr - 10);
      }

      // Labels & HUD
      ctx.font = `900 10px ${TECH_FONT}`;
      ctx.fillStyle = T.accent;
      ctx.textAlign = "center";
      ctx.fillText("UNIT: PRESSURE VESSEL", cx, cy + 4);
      
      // Indicators for Hoop Stress
      ctx.strokeStyle = T.orange;
      ctx.lineWidth = 2;
      const startA = -0.2, endA = 0.2;
      ctx.beginPath(); ctx.arc(cx, cy, dr + ww + 10, startA, endA); ctx.stroke();
      ctx.beginPath(); ctx.arc(cx, cy, dr + ww + 10, startA + Math.PI, endA + Math.PI); ctx.stroke();
      
      ctx.font = `bold 9px ${MONO_FONT}`;
      ctx.fillStyle = T.orange;
      ctx.fillText("STR: HOOP", cx + dr + 35, cy);
      
      ctx.fillStyle = wallColor;
      ctx.font = `900 11px ${TECH_FONT}`;
      ctx.fillText(safe ? "STATUS: STABLE" : warn ? "STATUS: MARGINAL" : "STATUS: CRITICAL", cx, H - 15);
      ctx.textAlign = "left";

    },
    [pressure, thickness, radius, mat, hoop, ys, fos],
    { animate: true }
  );

  const buildPrompt = useCallback(() =>
    `Pressure vessel structural integrity simulation ΓÇö current parameters:
ROLE: "You are an expert in structural safety. You have deep knowledge of DRDO, HEMRL, and Indian defense R&D programs."

PARAMETERS (numbered):
1. Material: ${mat}
2. Yield strength: ${ys} MPa
3. Internal pressure: ${pressure} MPa
4. Wall thickness: ${thickness} mm
5. Inner radius: ${radius} mm
6. Hoop stress (╧â_h): ${hoop.toFixed(0)} MPa
7. Axial stress: ${axial.toFixed(0)} MPa
8. Factor of Safety: ${fos.toFixed(2)}
9. Burst pressure: ${burst} MPa
10. Status: ${!safe && !warn ? "YIELDED" : warn ? "CAUTION" : "SAFE"}

ANALYSIS REQUEST:
Part 1 ΓÇö PERFORMANCE: Analyze these parameters. Are they realistic? What performance regime do they represent (low/medium/high)? What is the efficiency?
Part 2 ΓÇö SAFETY & RISK: What are the safety margins? What failure modes exist at these conditions? What would a test engineer watch for?
Part 3 ΓÇö INDIA-SPECIFIC CONTEXT: How does this relate to DRDO/HEMRL programs? Reference specific Indian systems (e.g., Agni, BrahMos, Pinaka, SMART, Astra, Nag, Akash) where applicable. What are India's current capabilities and gaps in this domain?`,
  [mat, ys, pressure, thickness, radius, hoop, axial, fos, burst, safe, warn]);

  return (
    <div>
      <SimCanvas canvasRef={canvasRef} width={280} height={200} maxWidth={280} />
      <PillRow>
        <Pill active={mat === "steel"} onClick={() => setMat("steel")}>Steel 700MPa</Pill>
        <Pill active={mat === "aluminium"} onClick={() => setMat("aluminium")} color={T.gold}>Al 280MPa</Pill>
        <Pill active={mat === "composite"} onClick={() => setMat("composite")} color={T.green}>CFRP 450MPa</Pill>
      </PillRow>
      <Slider label="Internal Pressure" value={pressure} onChange={setPressure} min={1} max={25} step={0.5} unit=" MPa" color={T.accent} />
      <Slider label="Wall Thickness" value={thickness} onChange={setThickness} min={2} max={30} step={0.5} unit=" mm" color={T.orange} />
      <Slider label="Inner Radius" value={radius} onChange={setRadius} min={50} max={500} step={10} unit=" mm" color={T.gold} />
      <DataRow>
        <DataBox label="Hoop ╧â" value={hoop.toFixed(0)} unit="MPa" color={hoop > ys ? T.red : T.orange} />
        <DataBox label="Axial ╧â" value={axial.toFixed(0)} unit="MPa" color={T.accent} />
        <DataBox label="FoS" value={fos.toFixed(1)} unit="├ù" color={safe ? T.green : warn ? T.gold : T.red} />
        <DataBox label="Burst" value={burst} unit="MPa" color={T.red} />
      </DataRow>
      <InfoBox>
        <strong style={{ color: T.accent }}>╧â_hoop = P├ùr/t.</strong> Orange arrows = circumferential stress. ASME requires FoS ΓëÑ 1.5. Wall color: <span style={{ color: T.green }}>safe</span> / <span style={{ color: T.gold }}>caution</span> / <span style={{ color: T.red }}>yield exceeded</span>.
      </InfoBox>
      <AIInsight buildPrompt={buildPrompt} color={T.accent} />
      <ExportBtn simId="pressure_vessel" getData={() => ({ mat, pressure, thickness, radius, hoop: hoop.toFixed(0), axial: axial.toFixed(0), fos: fos.toFixed(2) })} color={T.accent} />
    </div>
  );
}

import { useState, useCallback } from "react";
import { T, TECH_FONT, MONO_FONT, useCanvas, getCanvasTheme, prng } from "../utils";

export default function PropellantChemistrySim() {
  const [oxidizer, setOxidizer] = useState("ap");
  const [binder, setBinder] = useState("htpb");
  const [alPercent, setAlPercent] = useState(18);
  const [nano, setNano] = useState(false);

  const oxData = { ap: { isp: 260, green: false }, an: { isp: 220, green: true }, adn: { isp: 275, green: true }, hmx: { isp: 285, green: false } };
  const bindData = { htpb: { isp: 0 }, gap: { isp: 15 }, pban: { isp: -5 } };
  const oxcol = { ap: "#4A90D9", an: T.green, adn: T.purple, hmx: T.red };
  const ox = oxData[oxidizer], bn = bindData[binder];
  const totalIsp = (ox.isp + bn.isp + alPercent * 1.2 + (nano ? 12 : 0)).toFixed(0);
  const density = (ox.isp > 260 ? 1.91 : 1.8) * 0.7 + (2.7 * alPercent) / 100 + 0.92 * 0.3;
  const sensitivity = oxidizer === "hmx" ? "HIGH" : oxidizer === "ap" ? "MED" : "LOW";
  const greenScore = (ox.green ? 70 : 20) + (binder === "gap" ? 15 : 0);

  const canvasRef = useCanvas((ctx, W, H, frame) => {
    const theme = getCanvasTheme();

    // Background for chemistry scene
    const bg = ctx.createRadialGradient(W/2, H/2, 0, W/2, H/2, W/2);
    bg.addColorStop(0, theme.canvasBackground);
    bg.addColorStop(1, theme.canvasSurface);
    ctx.fillStyle = bg;
    ctx.fillRect(0, 0, W, H);

    const cx = 80, cy = H / 2, r = 50;
    
    // Molecular Matrix Container
    ctx.strokeStyle = `${T.accent}30`;
    ctx.lineWidth = 1;
    ctx.strokeRect(20, 20, 120, H - 40);
    
    // Matrix Grains (Simulated Solid Matrix)
    const grainCount = 100;
    for(let i=0; i<grainCount; i++) {
      const gx = 25 + (i % 10) * 11;
      const gy = 25 + Math.floor(i / 10) * 10;
      
      const seed = Math.sin(i * 0.5 + performance.now() / 500);
      let col = "#A0522D"; // Binder default
      
      const p = i / grainCount;
      if (p < (ox.isp / 300)) col = oxcol[oxidizer];
      else if (p < (ox.isp / 300) + alPercent / 50) col = "#C0C0C0";
      
      ctx.fillStyle = col;
      ctx.globalAlpha = 0.6 + seed * 0.2;
      ctx.fillRect(gx, gy, 9, 8);
    }
    ctx.globalAlpha = 1;

    // Energy Density Spectrum (Right Side)
    const sx = 160, sy = 30, sw = W - 180, sh = H - 60;
    ctx.strokeStyle = `${T.accent}20`;
    ctx.strokeRect(sx, sy, sw, sh);
    
    // Grid Lines
    ctx.beginPath();
    for(let y=sy; y<sy+sh; y+=20) { ctx.moveTo(sx, y); ctx.lineTo(sx+sw, y); }
    ctx.stroke();

    // Stability Plot
    ctx.strokeStyle = T.accent;
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(sx, sy + sh * 0.8);
    for(let x=0; x<sw; x+=5) {
      const iy = Math.sin(x * 0.1 + performance.now() / 200) * 5 * (sensitivity === "HIGH" ? 3 : 1);
      ctx.lineTo(sx + x, sy + sh * 0.8 - (totalIsp / 350) * sh * 0.5 + iy);
    }
    ctx.stroke();
    
    // Nano-Enhancement Twinkle
    if (nano) {
      for(let i=0; i<15; i++) {
        const nx = 20 + prng(frame, i * 2)     * 120;
        const ny = 20 + prng(frame, i * 2 + 1) * (H-40);
        const s = Math.sin(performance.now() / 150 + i) * 0.5 + 0.5;
        ctx.fillStyle = T.gold;
        ctx.globalAlpha = s;
        ctx.beginPath(); ctx.arc(nx, ny, 1, 0, Math.PI * 2); ctx.fill();
      }
      ctx.globalAlpha = 1;
    }

    // HUD Text
    ctx.font = `900 9px ${TECH_FONT}`;
    ctx.fillStyle = T.accent;
    ctx.fillText("MATRIX: PROP-LOAD", 20, 15);
    ctx.fillText("ENERGY SPECTRUM (Isp)", sx, 25);
    
    ctx.font = `800 8px ${MONO_FONT}`;
    ctx.fillStyle = T.dimText;
    ctx.fillText(`MODE: ${nano ? "NANO-ENHANCED" : "STANDARD"}`, 160, H - 15);

  }, [oxidizer, binder, alPercent, nano, totalIsp, sensitivity],
    { animate: true }
  );

  const buildPrompt = useCallback(() =>
    `Solid propellant chemistry formulation simulation ΓÇö current parameters:
ROLE: "You are an expert in energetic materials chemistry. You have deep knowledge of DRDO, HEMRL, and Indian defense R&D programs."

PARAMETERS (numbered):
1. Oxidizer: ${oxidizer.toUpperCase()}
2. Oxidizer Isp contribution: ${ox.isp} s
3. Oxidizer green chemistry: ${ox.green ? "YES" : "NO"}
4. Binder: ${binder.toUpperCase()}
5. Binder Isp contribution: ${bn.isp} s
6. Aluminium fuel: ${alPercent}%
7. Nano-aluminium: ${nano ? "YES (3-5├ù burn rate enhancement)" : "NO"}
8. Total formulated Isp: ${totalIsp} s
9. Sensitivity level: ${sensitivity}
10. Green score: ${greenScore}%

ANALYSIS REQUEST:
Part 1 ΓÇö PERFORMANCE: Analyze these parameters. Are they realistic? What performance regime do they represent (low/medium/high)? What is the efficiency?
Part 2 ΓÇö SAFETY & RISK: What are the safety margins? What failure modes exist at these conditions? What would a test engineer watch for?
Part 3 ΓÇö INDIA-SPECIFIC CONTEXT: How does this relate to DRDO/HEMRL programs? Reference specific Indian systems (e.g., Agni, BrahMos, Pinaka, SMART, Astra, Nag, Akash) where applicable. What are India's current capabilities and gaps in this domain?`,
  [oxidizer, ox, binder, bn, alPercent, nano, totalIsp, sensitivity, greenScore]);

  return (<div>
    <SimCanvas canvasRef={canvasRef} width={320} height={150} maxWidth={320} />
    <PillRow>
      <Pill active={oxidizer === "ap"} onClick={() => setOxidizer("ap")} color={T.accent}>AP</Pill>
      <Pill active={oxidizer === "an"} onClick={() => setOxidizer("an")} color={T.green}>AN ΓÖ╗</Pill>
      <Pill active={oxidizer === "adn"} onClick={() => setOxidizer("adn")} color={T.purple}>ADN ΓÖ╗</Pill>
      <Pill active={oxidizer === "hmx"} onClick={() => setOxidizer("hmx")} color={T.red}>HMX</Pill>
    </PillRow>
    <PillRow>
      <Pill active={binder === "htpb"} onClick={() => setBinder("htpb")} color={T.gold}>HTPB</Pill>
      <Pill active={binder === "gap"} onClick={() => setBinder("gap")} color={T.orange}>GAP</Pill>
      <Pill active={binder === "pban"} onClick={() => setBinder("pban")} color={T.gray}>PBAN</Pill>
      <Pill active={nano} onClick={() => setNano(!nano)} color={T.gold}>{nano ? "Nano ΓùÅ" : "Nano Γùï"}</Pill>
    </PillRow>
    <Slider label="Aluminium %" value={alPercent} onChange={setAlPercent} min={0} max={30} unit="%" color={T.gray} />
    <DataRow>
      <DataBox label="Isp" value={totalIsp} unit="s" color={T.accent} />
      <DataBox label="Density" value={density.toFixed(2)} unit="g/cc" color={T.gold} />
      <DataBox label="Sensitivity" value={sensitivity} color={sensitivity === "HIGH" ? T.red : sensitivity === "MED" ? T.gold : T.green} />
      <DataBox label="Green" value={`${greenScore}%`} color={greenScore > 50 ? T.green : T.orange} />
    </DataRow>
    <InfoBox><strong style={{ color: T.purple }}>Formulation:</strong> Oxidizer ({oxidizer.toUpperCase()}) + Binder ({binder.toUpperCase()}) + Al fuel. {ox.green ? "ΓÖ╗ Green oxidizer ΓÇö reduced HCl emissions." : ""} {nano ? "Nano-Al increases burn rate 3-5├ù via surface area." : ""} HEMRL leads India's energetic materials synthesis.</InfoBox>
    <AIInsight buildPrompt={buildPrompt} color={T.purple} />
    <ExportBtn simId="propellant_chemistry" getData={() => ({ oxidizer, binder, alPercent, nano, totalIsp, density })} color={T.purple} />
  </div>);
}

import { useState, useMemo, useCallback } from "react";
import { T, TECH_FONT, MONO_FONT, useCanvas, getCanvasTheme, prng } from "../utils";

export default function ScramjetSim() {
  const [mach, setMach] = useState(6);
  const [fuelType, setFuelType] = useState("hydrogen");
  const [altitude, setAltitude] = useState(25);
  const [cooling, setCooling] = useState(true);

  const temp = useMemo(() => Math.round(288 * (1 + 0.2 * mach * mach)), [mach]);
  const { thrustN, eta, Pt2, Ve, Tcomb, T_atm } = useMemo(() => {
    const fuelHeat = fuelType === "hydrogen" ? 2200 : fuelType === "jp7" ? 1400 : 1600;
    const V0 = mach * 340;
    const P_atm = 101325 * Math.exp(-altitude / 8.5);
    const T_atm = 288 - 6.5 * Math.min(altitude, 11);
    const Pt2 = P_atm * Math.pow(1 + 0.2 * mach * mach, 3.5);
    const Tcomb = temp + fuelHeat;
    const Ve = Math.sqrt(2 * 1005 * Tcomb * (1 - Math.pow(P_atm / Pt2, 0.286)));
    const F_sp = Ve - V0;
    const mdot = 0.5 + mach * 0.3;
    const thrustN = Math.max(0, Math.round(F_sp * mdot / 1000));
    const eta = Math.round((1 - T_atm / Tcomb) * 100);
    return { thrustN, eta, Pt2, Ve, Tcomb, T_atm };
  }, [mach, fuelType, altitude, temp]);
  const wallT = useMemo(() => {
    const base = temp * 0.6;
    return Math.round(cooling ? base * 0.35 : base);
  }, [temp, cooling]);

  const canvasRef = useCanvas((ctx, W, H, frame) => {
    const cy = H / 2;
    
    // Background Radial Gradient for hypersonic atmosphere
    const theme = getCanvasTheme();
    const bgGrad = ctx.createRadialGradient(W/2, cy, 0, W/2, cy, W);
    bgGrad.addColorStop(0, theme.canvasBackground);
    bgGrad.addColorStop(1, theme.canvasSurface);
    ctx.fillStyle = bgGrad;
    ctx.fillRect(0, 0, W, H);

    // Inlet / Cowl Structure
    ctx.fillStyle = "#2D3748";
    ctx.strokeStyle = `${T.accent}40`;
    ctx.lineWidth = 1.5;
    
    ctx.beginPath(); 
    ctx.moveTo(20, cy - 40); ctx.lineTo(100, cy - 20); ctx.lineTo(100, cy + 20); ctx.lineTo(20, cy + 40); 
    ctx.closePath(); ctx.fill(); ctx.stroke();

    // Isolator & Combustor Housing
    ctx.fillStyle = "#1A202C";
    ctx.fillRect(100, cy - 20, 160, 40);
    ctx.strokeRect(100, cy - 20, 160, 40);

    // Aero-heating Glow (Leading Edge)
    if (mach > 5) {
      const heatAlpha = Math.min(1, (mach - 5) / 7);
      ctx.shadowBlur = 15;
      ctx.shadowColor = T.red;
      ctx.strokeStyle = `rgba(255, 69, 58, ${heatAlpha})`;
      ctx.lineWidth = 2;
      ctx.beginPath(); ctx.moveTo(20, cy - 40); ctx.lineTo(25, cy - 41); ctx.stroke();
      ctx.beginPath(); ctx.moveTo(20, cy + 40); ctx.lineTo(25, cy + 41); ctx.stroke();
      ctx.shadowBlur = 0;
    }

    // Oblique Shock Waves (Inlet)
    ctx.strokeStyle = `${T.cyan}${Math.floor(20 + mach * 10).toString(16)}`;
    ctx.lineWidth = 1;
    for (let i = 0; i < 3; i++) {
      ctx.beginPath();
      ctx.moveTo(20, cy - 40);
      ctx.lineTo(60 + i * 15, cy - 10 + i * 5);
      ctx.stroke();
      ctx.beginPath();
      ctx.moveTo(20, cy + 40);
      ctx.lineTo(60 + i * 15, cy + 10 - i * 5);
      ctx.stroke();
    }

    // Supersonic Combustion Flame
    const flameGrad = ctx.createLinearGradient(130, 0, 260, 0);
    flameGrad.addColorStop(0, T.white);
    flameGrad.addColorStop(0.2, T.orange);
    flameGrad.addColorStop(1, "transparent");
    
    ctx.fillStyle = flameGrad;
    ctx.globalAlpha = 0.6 + prng(frame, 1) * 0.2;
    ctx.beginPath();
    ctx.roundRect(130, cy - 15, 130 + mach * 5, 30, 4);
    ctx.fill();
    ctx.globalAlpha = 1;

    // Sparks / High-velocity particles
    for (let i = 0; i < 12; i++) {
      const px = 140 + prng(frame, i * 3)     * 150;
      const py = cy + (prng(frame, i * 3 + 1) - 0.5) * 25;
      ctx.fillStyle = `rgba(255, 200, 100, ${prng(frame, i * 3 + 2) * 0.8})`;
      ctx.fillRect(px, py, 4 + prng(frame, i * 3 + 2) * 10, 1);
    }

    // Cooling Jacket Visualization
    if (cooling) {
      ctx.shadowBlur = 10;
      ctx.shadowColor = T.cyan;
      ctx.strokeStyle = `${T.cyan}88`;
      ctx.lineWidth = 2;
      ctx.setLineDash([5, 5]);
      ctx.strokeRect(100, cy - 25, 160, 50);
      ctx.setLineDash([]);
      ctx.shadowBlur = 0;
      
      ctx.font = `900 8px ${TECH_FONT}`;
      ctx.fillStyle = T.cyan;
      ctx.fillText("COOLANT FLOW ACTIVE", 110, cy - 28);
    }

    // Divergent Nozzle / Expansion
    ctx.fillStyle = "#2D3748";
    ctx.beginPath();
    ctx.moveTo(260, cy - 20); ctx.lineTo(340, cy - 45); ctx.lineTo(340, cy + 45); ctx.lineTo(260, cy + 20);
    ctx.closePath(); ctx.fill();
    ctx.strokeStyle = `${T.accent}40`;
    ctx.stroke();

    // Expansion Fan / Exhaust
    const exhaustGrad = ctx.createLinearGradient(340, 0, 410, 0);
    exhaustGrad.addColorStop(0, `${T.accent}44`);
    exhaustGrad.addColorStop(1, "transparent");
    ctx.fillStyle = exhaustGrad;
    ctx.beginPath();
    ctx.moveTo(340, cy - 40); ctx.lineTo(410, cy - 60); ctx.lineTo(410, cy + 60); ctx.lineTo(340, cy + 40);
    ctx.fill();

    // Labels
    ctx.font = `900 10px ${TECH_FONT}`;
    ctx.textAlign = "center";
    ctx.fillStyle = T.cyan; ctx.fillText("SUPERSONIC INLET", 60, cy + 55);
    ctx.fillStyle = T.gray; ctx.fillText("ISOLATOR", 115, cy + 55);
    ctx.fillStyle = T.orange; ctx.fillText("SCRAM-COMBUSTOR", 200, cy + 55);
    ctx.fillStyle = T.accent; ctx.fillText("EXPANSION NOZZLE", 310, cy + 55);
    ctx.textAlign = "left";
    
    // Mach Vector Overlay
    ctx.strokeStyle = T.white;
    ctx.lineWidth = 2;
    ctx.beginPath(); ctx.moveTo(10, cy); ctx.lineTo(40, cy); ctx.stroke();
    ctx.beginPath(); ctx.moveTo(40, cy); ctx.lineTo(35, cy-3); ctx.moveTo(40, cy); ctx.lineTo(35, cy+3); ctx.stroke();
    ctx.font = `bold 9px ${MONO_FONT}`;
    ctx.fillStyle = T.white;
    ctx.fillText(`M${mach}`, 10, cy - 8);

  }, [mach, fuelType, cooling],
    { animate: true }
  );

  const buildPrompt = useCallback(() =>
    `Scramjet (supersonic combustion ramjet) simulation ΓÇö current parameters:
ROLE: "You are an expert in hypersonic propulsion. You have deep knowledge of DRDO, HEMRL, and Indian defense R&D programs."

PARAMETERS (numbered):
1. Flight Mach number: ${mach}
2. Fuel type: ${fuelType}
3. Altitude: ${altitude} km
4. Active regenerative cooling: ${cooling ? "YES" : "NO"}
5. Stagnation temperature: ${temp} K
6. Thermal efficiency: ${eta} %
7. Inlet total pressure: ${(Pt2 / 1e6).toFixed(2)} MPa
8. Exit velocity (Ve): ${Math.round(Ve)} m/s
9. Combustor total temperature: ${Tcomb} K
10. Net thrust: ${thrustN} kN
11. Combustor wall temperature: ${wallT} K

ANALYSIS REQUEST:
Part 1 ΓÇö PERFORMANCE: Analyze these parameters. Are they realistic? What performance regime do they represent (low/medium/high)? What is the efficiency?
Part 2 ΓÇö SAFETY & RISK: What are the safety margins? What failure modes exist at these conditions? What would a test engineer watch for?
Part 3 ΓÇö INDIA-SPECIFIC CONTEXT: How does this relate to DRDO/HEMRL programs? Reference specific Indian systems (e.g., Agni, BrahMos, Pinaka, SMART, Astra, Nag, Akash) where applicable. What are India's current capabilities and gaps in this domain?`,
  [mach, fuelType, altitude, cooling, temp, eta, Pt2, Ve, Tcomb, thrustN, wallT]);

  return (<div>
    <SimCanvas canvasRef={canvasRef} width={420} height={130} maxWidth={420} />
    <PillRow>
      <Pill active={fuelType === "hydrogen"} onClick={() => setFuelType("hydrogen")} color={T.green}>Hydrogen</Pill>
      <Pill active={fuelType === "jp7"} onClick={() => setFuelType("jp7")} color={T.orange}>JP-7</Pill>
      <Pill active={fuelType === "ethylene"} onClick={() => setFuelType("ethylene")} color={T.cyan}>Ethylene</Pill>
      <Pill active={cooling} onClick={() => setCooling(!cooling)} color={T.cyan}>{cooling ? "Cooling ON" : "Cooling OFF"}</Pill>
    </PillRow>
    <Slider label="Mach Number" value={mach} onChange={setMach} min={4} max={12} step={0.5} unit="" color={T.orange} />
    <Slider label="Altitude" value={altitude} onChange={setAltitude} min={0} max={30} unit=" km" color={T.accent} />
    <DataRow>
      <DataBox label="Stagnation T" value={temp} unit="K" color={temp > 2500 ? T.red : T.orange} />
      <DataBox label="╬╖_thermal" value={eta} unit="%" color={T.green} />
      <DataBox label="Inlet Pt" value={(Pt2 / 1e6).toFixed(1)} unit="MPa" color={T.purple} />
      <DataBox label="Ve" value={Math.round(Ve)} unit="m/s" color={T.cyan} />
      <DataBox label="Thrust" value={thrustN} unit="kN" color={T.green} />
      <DataBox label="Wall T" value={wallT} unit="K" color={wallT > 800 ? T.red : T.cyan} />
    </DataRow>
    <InfoBox><strong style={{ color: T.cyan }}>Scramjet:</strong> Air-breathing, supersonic combustion at Mach 5+. Uses atmospheric OΓéé. {cooling ? "Active cooling circulates fuel through the combustor walls to protect materials." : "ΓÜá Without cooling, walls exceed material limits above Mach 7."} DRDL tested 12-min full-scale run in Jan 2026.</InfoBox>
    <AIInsight buildPrompt={buildPrompt} color={T.cyan} />
    <ExportBtn simId="scramjet" getData={() => ({ mach, fuelType, altitude, cooling, thrustN, eta, Ve })} color={T.cyan} />
  </div>);
}

import { useState, useMemo, useCallback } from "react";
import { T, TECH_FONT, useCanvas, getCanvasTheme } from "../utils";

export default function ShapedChargeSim() {
  const [liner, setLiner] = useState("copper");
  const [coneAngle, setConeAngle] = useState(42);
  const [standoff, setStandoff] = useState(3);
  const [explosive, setExplosive] = useState("rdx");

  // ΓöÇΓöÇ Physics ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const physics = useMemo(() => {
    const VoDMap = { rdx: 8750, hmx: 9100 };
    const linerDensityMap = { copper: 8960, tantalum: 16650, steel: 7850 };

    const VoD = VoDMap[explosive];
    const linerDensity = linerDensityMap[liner];
    const halfAngleRad = (coneAngle * Math.PI) / 360;

    // Munroe-effect jet & slug velocities
    const Vjet = VoD * Math.cos(halfAngleRad);
    const Vslug = VoD * Math.sin(halfAngleRad) * 0.3;

    // Birkhoff-Eichelberger penetration
    const linerLength = 80 / Math.tan(halfAngleRad); // mm
    const P = linerLength * Math.sqrt(linerDensity / 7850);

    // Standoff optimality factor
    const rawFactor = 1 - 0.05 * Math.pow(standoff - 3, 2);
    const standoffFactor = Math.min(1.0, Math.max(0.3, rawFactor));
    const Peff = Math.round(P * standoffFactor);

    return { Vjet, Vslug, P, standoffFactor, Peff, linerDensity };
  }, [liner, coneAngle, standoff, explosive]);

  // ΓöÇΓöÇ Canvas ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const canvasRef = useCanvas(
    (ctx, W, H) => {
      const canvasTheme = getCanvasTheme();

      // Background
      const bgGlow = ctx.createRadialGradient(W / 2, H / 2, 0, W / 2, H / 2, W / 2);
      bgGlow.addColorStop(0, `${T.red}08`);
      bgGlow.addColorStop(1, "transparent");
      ctx.fillStyle = canvasTheme.panelFill;
      ctx.fillRect(0, 0, W, H);
      ctx.fillStyle = bgGlow;
      ctx.fillRect(0, 0, W, H);

      // ΓöÇΓöÇ Colour helpers ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
      const linerColor = liner === "copper" ? "#b87333" : liner === "tantalum" ? "#8899aa" : "#aab0b8";
      const explColor  = explosive === "rdx" ? "#c0392b" : "#8e44ad";

      // ΓöÇΓöÇ Shaped charge body (left-centre) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
      const bodyX = 30, bodyY = 30, bodyW = 100, bodyH = H - 60;
      const cx = bodyX + bodyW / 2;

      // Cylindrical explosive body
      const bodyGrad = ctx.createLinearGradient(bodyX, 0, bodyX + bodyW, 0);
      bodyGrad.addColorStop(0, `${explColor}55`);
      bodyGrad.addColorStop(0.5, explColor);
      bodyGrad.addColorStop(1, `${explColor}55`);
      ctx.fillStyle = bodyGrad;
      ctx.strokeStyle = `${T.red}80`;
      ctx.lineWidth = 1.5;
      ctx.beginPath();
      ctx.roundRect(bodyX, bodyY, bodyW, bodyH, 6);
      ctx.fill();
      ctx.stroke();

      // Detonator (top, red circle)
      ctx.shadowBlur = 12;
      ctx.shadowColor = T.red;
      ctx.fillStyle = T.red;
      ctx.beginPath();
      ctx.arc(cx, bodyY + 10, 7, 0, Math.PI * 2);
      ctx.fill();
      ctx.shadowBlur = 0;

      // Conical liner (V-shape at bottom of charge)
      const halfAngleRad = (coneAngle * Math.PI) / 360;
      const coneHeight = Math.min(bodyH * 0.55, 70 / Math.tan(halfAngleRad));
      const coneBaseY  = bodyY + bodyH;
      const coneHalfW  = coneHeight * Math.tan(halfAngleRad);
      const coneTipX   = cx;
      const coneTipY   = coneBaseY - coneHeight;

      const linerGrad = ctx.createLinearGradient(cx - coneHalfW, 0, cx + coneHalfW, 0);
      linerGrad.addColorStop(0, `${linerColor}88`);
      linerGrad.addColorStop(0.5, linerColor);
      linerGrad.addColorStop(1, `${linerColor}88`);
      ctx.fillStyle = linerGrad;
      ctx.strokeStyle = `${linerColor}cc`;
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.moveTo(cx - coneHalfW, coneBaseY);
      ctx.lineTo(coneTipX, coneTipY);
      ctx.lineTo(cx + coneHalfW, coneBaseY);
      ctx.closePath();
      ctx.fill();
      ctx.stroke();

      // ΓöÇΓöÇ Jet & slug (extending right from cone tip) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
      const standoffPx = Math.min(standoff * 18, W - bodyX - bodyW - 40);
      const jetStartX  = cx + bodyW / 2 + 4;
      const jetY       = coneTipY;
      const targetX    = bodyX + bodyW + standoffPx;

      // Jet glow line
      ctx.shadowBlur = 10;
      ctx.shadowColor = linerColor;
      const jetGrad = ctx.createLinearGradient(jetStartX, 0, targetX, 0);
      jetGrad.addColorStop(0, linerColor);
      jetGrad.addColorStop(1, "transparent");
      ctx.strokeStyle = jetGrad;
      ctx.lineWidth = 3;
      ctx.beginPath();
      ctx.moveTo(jetStartX, jetY);
      ctx.lineTo(targetX, jetY);
      ctx.stroke();

      // Slug (thicker blob just behind jet head)
      const slugX = jetStartX + (targetX - jetStartX) * 0.25;
      ctx.fillStyle = linerColor;
      ctx.globalAlpha = 0.7;
      ctx.beginPath();
      ctx.ellipse(slugX, jetY, 10, 4, 0, 0, Math.PI * 2);
      ctx.fill();
      ctx.globalAlpha = 1;
      ctx.shadowBlur = 0;

      // ΓöÇΓöÇ Target plate ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
      const targetW = 18;
      const targetH = H - 40;
      const penetrationFrac = Math.min(physics.Peff / 300, 1); // normalise to 300 mm max
      const penetrationPx   = penetrationFrac * targetW;

      ctx.fillStyle = "#607080";
      ctx.strokeStyle = `${T.gray}80`;
      ctx.lineWidth = 1;
      ctx.beginPath();
      ctx.roundRect(targetX, 20, targetW, targetH, 3);
      ctx.fill();
      ctx.stroke();

      // Penetration channel in target
      if (physics.Peff > 0) {
        ctx.fillStyle = canvasTheme.canvasSurface;
        ctx.beginPath();
        ctx.roundRect(targetX, jetY - 5, penetrationPx + 2, 10, 2);
        ctx.fill();
        // Spall glow at penetration front
        ctx.shadowBlur = 8;
        ctx.shadowColor = T.orange;
        ctx.fillStyle = T.orange;
        ctx.beginPath();
        ctx.arc(targetX + penetrationPx, jetY, 4, 0, Math.PI * 2);
        ctx.fill();
        ctx.shadowBlur = 0;
      }

      // ΓöÇΓöÇ Labels ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
      ctx.textAlign = "left";
      ctx.font = `900 9px ${TECH_FONT}`;
      ctx.fillStyle = T.accent;
      ctx.fillText("SHAPED CHARGE", bodyX, bodyY - 6);

      ctx.fillStyle = T.gray;
      ctx.font = `600 8px ${TECH_FONT}`;
      ctx.fillText(`STANDOFF: ${standoff} CD`, jetStartX + 2, jetY - 10);

      ctx.fillStyle = linerColor;
      ctx.fillText(liner.toUpperCase() + " LINER", bodyX, coneBaseY + 12);

      ctx.fillStyle = T.red;
      ctx.fillText("DET", cx - 10, bodyY + 28);

      ctx.fillStyle = T.dimText ?? "#88a0b8";
      ctx.textAlign = "center";
      ctx.fillText("RHA TARGET", targetX + targetW / 2, 16);
    },
    [liner, coneAngle, standoff, explosive, physics]
  );

  // ΓöÇΓöÇ AI prompt ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const buildPrompt = useCallback(
    () =>
      `Shaped charge warhead engineering simulation ΓÇö current parameters:
ROLE: "You are an expert in shaped charge warhead engineering, terminal ballistics, and DRDO anti-armour programs. You have deep knowledge of the Munroe effect, Birkhoff-Eichelberger penetration theory, and Indian defence R&D."

PARAMETERS (numbered):
1. Liner material: ${liner} (density ${liner === "copper" ? 8960 : liner === "tantalum" ? 16650 : 7850} kg/m┬│)
2. Cone half-angle: ${coneAngle / 2}┬░ (full apex angle: ${coneAngle}┬░)
3. Standoff distance: ${standoff} caliber diameters (CD)
4. Explosive fill: ${explosive.toUpperCase()} (VoD: ${explosive === "rdx" ? 8750 : 9100} m/s)
5. Jet velocity (Vjet): ${(physics.Vjet / 1000).toFixed(2)} km/s
6. Slug velocity: ${Math.round(physics.Vslug)} m/s
7. Effective penetration: ${physics.Peff} mm RHA
8. Standoff efficiency factor: ${(physics.standoffFactor * 100).toFixed(0)}%

ANALYSIS REQUEST:
Part 1 ΓÇö PERFORMANCE: Evaluate these parameters. What jet tip velocity regime does this represent? How does liner density affect penetration? Is the standoff optimal?
Part 2 ΓÇö SAFETY & RISK: What are the key failure modes (jet break-up, precursor effects, target obliquity)? What safety considerations apply to shaped charge assembly and handling?
Part 3 ΓÇö INDIA-SPECIFIC CONTEXT: How do these parameters relate to DRDO shaped charge programs? Reference specific Indian systems (e.g., Nag ATGM, Arjun MBT anti-tank rounds, Helina, MPATGM) where applicable. What are India's current capabilities and development focus in shaped charge warhead technology?`,
    [liner, coneAngle, standoff, explosive, physics]
  );

  const reset = () => {};

  return (
    <div>
      <SimCanvas canvasRef={canvasRef} width={460} height={220} maxWidth={460} />

      {/* Liner selector */}
      <PillRow>
        <Pill active={liner === "copper"}   onClick={() => setLiner("copper")}>≡ƒƒñ Copper</Pill>
        <Pill active={liner === "tantalum"} onClick={() => setLiner("tantalum")}>ΓÜ½ Tantalum</Pill>
        <Pill active={liner === "steel"}    onClick={() => setLiner("steel")}>≡ƒö⌐ Steel</Pill>
      </PillRow>

      {/* Cone-angle selector */}
      <PillRow>
        <Pill active={coneAngle === 42} onClick={() => setConeAngle(42)}>42┬░ (narrow)</Pill>
        <Pill active={coneAngle === 60} onClick={() => setConeAngle(60)}>60┬░ (standard)</Pill>
        <Pill active={coneAngle === 90} onClick={() => setConeAngle(90)}>90┬░ (wide)</Pill>
      </PillRow>

      {/* Explosive selector */}
      <PillRow>
        <Pill active={explosive === "rdx"} onClick={() => setExplosive("rdx")}>RDX</Pill>
        <Pill active={explosive === "hmx"} onClick={() => setExplosive("hmx")}>HMX</Pill>
      </PillRow>

      <Slider
        label="Standoff Distance"
        value={standoff}
        onChange={(v) => setStandoff(v)}
        min={1}
        max={20}
        step={0.5}
        unit=" CD"
        color={T.green}
      />

      <DataRow>
        <DataBox label="Jet Velocity" value={(physics.Vjet / 1000).toFixed(1)} unit="km/s"  color={T.red}    />
        <DataBox label="Penetration"  value={physics.Peff}                      unit="mm RHA" color={T.orange} />
        <DataBox label="Standoff ╬╖"   value={`${(physics.standoffFactor * 100).toFixed(0)}%`} color={T.green} />
        <DataBox label="Slug V"       value={Math.round(physics.Vslug)}          unit="m/s"   color={T.purple} />
      </DataRow>

      <InfoBox color={T.red}>
        Shaped charges use the <strong style={{ color: T.red }}>Munroe effect</strong> ΓÇö explosive-driven metal liner
        collapse forms a hypervelocity jet. DRDO's anti-tank munitions (Nag ATGM) use copper-lined shaped charges.
        Optimal standoff is <strong>2ΓÇô4 CD</strong>.
      </InfoBox>

      <AIInsight buildPrompt={buildPrompt} color={T.red} />
    </div>
  );
}

